function detectParallelConflicts(message: any): string {
  const results = message.content
    .filter((block: any) => block.type === 'tool_result')
    .map((block: any) => block.content);

  // Example: Weather can't be sunny AND raining
  const weatherResults = results.filter((r: any) => r.weather);
  const sunny = weatherResults.some((r: any) => r.weather.includes('sunny'));
  const rainy = weatherResults.some((r: any) => r.weather.includes('rain'));

  if (sunny && rainy) {
    return 'HALUCINATION: Conflicting parallel tool results';
  }

  return 'No conflicts detected';
}

